mapper.update:
UPDATE store_daily_capacity_table
SET remain_cnt = remain_cnt - #{count}
WHERE pickup_point_id = #{pickupPointId}
  AND pickup_date = #{pickupDate}
  AND remain_cnt >= #{count}

UPDATE store_daily_capacity_table
SET remain_cnt = remain_cnt + #{count}
WHERE pickup_point_id = #{pickupPointId}
  AND pickup_date = #{pickupDate}
  AND remain_cnt + #{count} <= total_cnt

mapper.select:
SELECT total_cnt
FROM store_daily_capacity_table
WHERE pickup_point_id = #{pickupPointId}
  AND pickup_date = #{pickupDate}
LIMIT 1
